+
+    // =========================================================================
+    // INFO log on rejection
+    // =========================================================================
+
+    #[test]
+    fn info_log_on_eprocess_rejection() {
+        let handle = with_captured_tracing(|| {
+            let base = Instant::now();
+            let mut cfg = test_config();
+            cfg.min_observations_between = 1;
