+        );
+    }
+
+    // =========================================================================
+    // Counter verification
+    // =========================================================================
+
+    #[test]
+    fn counter_accessor_is_callable() {
+        let total = eprocess_rejections_total();
+        let _ = total.checked_add(0).expect("counter overflow");
+    }
