+    #[test]
+    fn counter_increments_on_rejection() {
+        let before = eprocess_rejections_total();
+
+        let base = Instant::now();
+        let mut cfg = test_config();
+        cfg.min_observations_between = 1;
+        let mut t = EProcessThrottle::new_at(cfg, base);
+
